module RefModule(clk, reset, load, serial_in, parallel_in, Q);
     input clk;
     input reset;
     input load;
     input serial_in;
     input [7:0] parallel_in;
     output reg [7:0] Q;

       wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
          if (reset)
               Q <= 8'b00000000;
          else if (load)
               Q <= parallel_in;
          else
               Q <= {serial_in, Q[7:1]};
     end
endmodule
